//! Scheduler contract storage slot calculations
//!
//! Storage layout verified from compiled contract via `forge inspect Scheduler storage-layout`
//!
//! Scheduler.sol storage layout (from forge inspect):
//! - Slot 0: id (uint256) - current highest call ID

destinations.snippet:
pub fn call_to_slot_mapping(call_id: u64) -> U256 {
    // keccak256(call_id || slot_8)
    let mut data = [0u8; 64];
    data[24..32].copy_from_slice(&call_id.to_be_bytes());
    data[32..64].copy_from_slice(&SCHEDULER_CALL_TO_SLOT_SLOT.to_be_bytes::<32>());
